function getAllFiles(dirPath, arrayOfFiles) {
    arrayOfFiles = arrayOfFiles || [];

    // Vérifier si le dossier existe
    if (!fs.existsSync(dirPath)) {
        node.warn('Dossier introuvable : ' + dirPath);
        return arrayOfFiles;
    }

    const files = fs.readdirSync(dirPath);

    files.forEach(function (file) {
        const fullPath = path.join(dirPath, file);

        if (fs.statSync(fullPath).isDirectory()) {
            // Si c'est un dossier → rentrer dedans
            arrayOfFiles = getAllFiles(fullPath, arrayOfFiles);
        } else if (file.endsWith('.json')) {
            // Si c'est un .json → ajouter à la liste
            arrayOfFiles.push(fullPath);
        }
    });

    return arrayOfFiles;
}

// Dossier racine
const rootDir = '/home/pi/irrigation_data/';

// Récupérer tous les fichiers .json
let files = getAllFiles(rootDir);

// Trier par nom de fichier A→Z (ancien → nouveau)
files.sort((a, b) => {
    const nameA = path.basename(a);
    const nameB = path.basename(b);
    return nameA.localeCompare(nameB);
});

// Stocker dans le contexte du flow
flow.set('fileList', files);
flow.set('currentIndex', 0);

// Vérifier si des fichiers existent
if (files.length === 0) {
    node.warn('Aucun fichier JSON trouvé');
    return null; // Arrêter le flow
}

// Continuer
node.warn(files.length + ' fichiers trouvés à synchroniser');
msg.payload = files.length;
return msg;

// Lire la liste et l'index depuis le contexte
const fileList = flow.get('fileList') || [];
const currentIndex = flow.get('currentIndex') || 0;

// Vérifier si on a traité tous les fichiers
if (currentIndex >= fileList.length) {
    node.warn('✅ Sync terminée - ' + fileList.length + ' fichiers traités');
    return [null, msg]; // → sortie 2 (cycle terminé)
}

// Prendre le fichier à l'index actuel
msg.filename = fileList[currentIndex];
msg.filepath = fileList[currentIndex];

node.warn('📂 Traitement fichier ' + (currentIndex + 1) + '/' + fileList.length + ' : ' + msg.filename);

return [msg, null]; // → sortie 1 (continuer)

const filepath = msg.filename;

try {
    let data = msg.payload;

    // ✅ Fichier vide → supprimer et passer au suivant
    if (!data || (typeof data === 'string' && data.trim() === '')) {
        node.warn('⚠️ Fichier vide, suppression : ' + filepath);
        fs.unlinkSync(filepath);
        let idx = flow.get('currentIndex') || 0;
        flow.set('currentIndex', idx + 1);
        return [null, msg]; // → sortie 2
    }

    if (typeof data === 'string') {
        data = JSON.parse(data);
    }

    if (Array.isArray(data)) {
        data = data[0];
    }

    msg.payload = data;
    msg.headers = {
        'Content-Type': 'application/json',
        'X-API-Key': 'b43a927062563945e4f4767c6cb2905d0ff2e97a4b77c2ad8d32cc831f1fde61'
    };
    msg.filename = filepath;
    node.warn('📤 Envoi fichier : ' + filepath);
    return [msg, null]; // → sortie 1

} catch (e) {
    node.error('❌ Erreur JSON : ' + e.message);
    try { fs.unlinkSync(filepath); } catch (e2) { }
    let idx = flow.get('currentIndex') || 0;
    flow.set('currentIndex', idx + 1);
    return [null, msg]; // → sortie 2
}

// Lire l'index actuel
let currentIndex = flow.get('currentIndex') || 0;

// Incrémenter
currentIndex = currentIndex + 1;

// Sauvegarder le nouvel index
flow.set('currentIndex', currentIndex);

// Info debug
node.warn('✅ Fichier traité - Index suivant : ' + currentIndex);

// Retourner msg vers Nœud 6
return msg;
